#include <bits/stdc++.h>
using namespace std;
int n,l[1000006],r[1000006];
void f1(int x){
    if(x==0)return;
    cout<<x<<' ';
    f1(l[x]);
    f1(r[x]);
}
void f2(int x){
    if(x==0)return;
    f2(l[x]);
    cout<<x<<' ';
    f2(r[x]);
}
void f3(int x){
    if(x==0)return;
    f3(l[x]);
    f3(r[x]);
    cout<<x<<' ';
}
int main(){
    cin>>n;
    for(int i=1;i<=n;i++)cin>>l[i]>>r[i];
    f1(1);
    cout<<endl;
    f2(1);
    cout<<endl;
    f3(1);
    return 0;
}
